 55	static int get_single_ue_id(void)
 56	{
 57	  rrc_gNB_ue_context_t *ue_context_p = NULL;
 58	  RB_FOREACH(ue_context_p, rrc_nr_ue_tree_s, &(RC.nrrrc[0]->rrc_ue_head)) {
