 64	/**
 65	 * @brief Trigger RRC Release for a specific UE
 66	 * @param buf: RRC UE ID
 67	 * @param debug: Debug flag
 68	 * @param prnt: Print function
 69	 * @return 0 on success, -1 on failure
 70	*/
 71	int rrc_gNB_trigger_release(char *buf, int debug, telnet_printfunc_t prnt) {
 72	  ue_id_t ue_id = -1;
 73	  protocol_ctxt_t ctxt;
 74	
 75	  if (!buf) {
 76	    ue_id = get_single_ue_id();
 77	    if (ue_id < 1) {
 78	      prnt("No UE found!\n");
 79	      ERROR_MSG_RET("No UE found!\n");
 80	    }
 81	  } else {
 82	    ue_id = strtol(buf, NULL, 10);
 83	    if (ue_id < 1 || ue_id >= 0xfffffe) {
 84	      prnt("UE ID needs to be [1,0xfffffe]\n");
 85	      ERROR_MSG_RET("UE ID needs to be [1,0xfffffe]\n");
 86	    }
 87	  }
 88	
 89	  /* get RRC and UE */
 90	  gNB_RRC_INST *rrc = RC.nrrrc[0];
 91	  rrc_gNB_ue_context_t *ue_context_p = rrc_gNB_get_ue_context(rrc, ue_id);
 92	  if (!ue_context_p) {
 93	    prnt("Could not find UE context associated with UE ID %lu\n", ue_id);
 94	    LOG_E(RRC, "Could not find UE context associated with UE ID %lu\n", ue_id);
 95	    return -1;
 96	  }
 97	  
 98	  gNB_RRC_UE_t *UE = &ue_context_p->ue_context;
 99	  PROTOCOL_CTXT_SET_BY_INSTANCE(&ctxt, 0, GNB_FLAG_YES, UE->rrc_ue_id, 0, 0);
100	  ctxt.eNB_index = 0;
101	
102	  rrc_gNB_generate_RRCRelease(&ctxt, ue_context_p);
103	  prnt("RRC Release triggered for UE %u\n", ue_id);
104	  
105	  return 0;
106	}
