137	        case SCHED_BATCH:
138	          snprintf(strschedp, sizeof(strschedp), "%s ", "batch");
139	          priority = (NICE_MAX - NICE_MIN + 1) + nice - NICE_MIN;
140	          break;
141	        case SCHED_RR:
142	          snprintf(strschedp, sizeof(strschedp), "%s ", "rt:rr");
143	          priority = priority - 99;
144	          break;
145	#ifdef SCHED_DEADLINE
146	        case SCHED_DEADLINE:
147	          snprintf(strschedp, sizeof(strschedp), "%s ", "rt:deadline");
148	          break;
149	#endif
150	        default:
